1411	    /// via `luaS_newlstr`, while long strings allocate a fresh TString each
1412	    /// call so distinct long strings keep distinct object identity (observable
1413	    /// via `string.format("%p", s)`). The parser separately deduplicates
1414	    /// long-string literals within a single chunk through `luaX_newstring`'s
1415	    /// `ls->h` anchor table.
1416	    ///
1417	    /// C: `luaS_newlstr` (and `luaS_new`, which calls `luaS_newlstr`)
1418	    /// macros.tsv: `luaS_new → state.intern_str(s)`
1419	    pub fn intern_str(&mut self, bytes: &[u8]) -> Result<GcRef<LuaString>, LuaError> {
1420	        if bytes.len() <= crate::string::MAX_SHORT_LEN {
1421	            if let Some(existing) = self.global().interned_lt.get(bytes) {
1422	                return Ok(existing.clone());
1423	            }
1424	            let _local = crate::string::new(self, bytes)?;
1425	            let new_ref = GcRef::new(LuaString::from_bytes(bytes.to_vec()));
1426	            self.global_mut()
1427	                .interned_lt
1428	                .insert(bytes.to_vec().into_boxed_slice(), new_ref.clone());
1429	            Ok(new_ref)
1430	        } else {
1431	            let new_ref = GcRef::new(LuaString::from_bytes(bytes.to_vec()));
1432	            // PORT NOTE: Phase-B byte tracking for `collectgarbage("count")`.
1433	            // C-Lua's `luaC_newobj` calls `luaM_malloc`, which adds
1434	            // `sizeof(TString) + len + 1` to `g->GCdebt`. Phases A–C bypass
1435	            // that allocator, so without explicit accounting the Lua-visible
1436	            // memory total never reflects string payload — gc.lua's
1437	            // string-keys-in-weak-tables block depends on observing the >8MB
1438	            // jump after allocating two 4MB strings. Short strings are
1439	            // interned (bounded in size) so they are not tracked here.
1440	            // `reclaim_dead_long_strings` later subtracts the size back out
1441	            // when the underlying `Rc` is dropped.
1442	            let size = bytes.len()
1443	                + std::mem::size_of::<LuaString>()
1444	                + std::mem::size_of::<usize>();
1445	            let mut g = self.global_mut();
1446	            g.gc_debt += size as isize;
1447	            g.gc_tracked_long_strings
1448	                .push((new_ref.downgrade(), size));
