/// bitmask. Returns 0 when no `__mode` is set or it is not a string.
fn extract_weak_mode(mt: &LuaTable) -> u8 {
    let entries = mt.entries.borrow();
    for (k, v) in entries.iter() {
        if let LuaValue::Str(ks) = k {
            if ks.as_bytes() == b"__mode" {
