    pub gckind: u8,

    // C: lu_byte gcstopem — Phase D
    pub gcstopem: bool,

    // C: lu_byte genminormul — Phase D generational tuning
    // types.tsv: global_State.genminormul → u8
    pub genminormul: u8,

    // C: lu_byte genmajormul — Phase D
    pub genmajormul: u8,

    // C: lu_byte gcstp — controls GC running (GCSTPGC etc.)
    pub gcstp: u8,

