    /// Allocate a Lua-side closure (compiled function + upvalue slots).
    pub fn new_lclosure(&mut self, proto: GcRef<LuaProto>, nupvals: usize) -> GcRef<LuaClosureLua> {
        let mut upvals = Vec::with_capacity(nupvals);
        for _ in 0..nupvals {
