// C: LUA_MINSTACK = 20  (lua.h)
// macros.tsv: LUA_MINSTACK → const LUA_MINSTACK: u32 = 20
pub(crate) const LUA_MINSTACK: usize = 20;

// C: #define BASIC_STACK_SIZE (2 * LUA_MINSTACK)  (lstate.h)
